mapper.select:
SELECT
    mpi.PRODUCT_ID as productId,
    mpi.PRODUCT_CODE as productCode,
    mpi.PRODUCT_CODE_NAME as productCodeName,
    mpi.VENDOR_CODE as vendorCode,
    mv.vendor_name as vendorName,
    mpi.STATUS as status
FROM MA_PRODUCT_ID mpi
LEFT JOIN MA_VENDOR mv ON mpi.vendor_code = mv.vendor_code
WHERE 1 = 1

    AND mpi.product_code =  #{productCode}


    AND mpi.product_code_name =  #{productCodeName}


    AND mv.vendor_name = #{vendorName}


    AND mpi.product_id = #{productId}


    and mpi.user_company_code = #{userCompanyCode}


    and mpi.user_company_code IS NULL

mapper.update:
UPDATE MA_PRODUCT_ID
SET
    product_code_name = #{productCodeName},
    status = #{status}
WHERE 1 = 1
AND product_id = #{productId}

    and user_company_code = #{userCompanyCode}


    and user_company_code IS NULL
